  1→import React, { useState, useEffect } from 'react';
  2→import { Search, ShieldCheck, TrendingUp, Sparkles, Globe, Bot, BarChart3, CheckCircle } from 'lucide-react';
  3→import PageHeader from '../components/layout/PageHeader';
  4→
  5→const analysisSteps = [
  6→  { icon: Globe, label: 'Crawl du site web...', duration: 2000 },
  7→  { icon: Bot, label: 'Interrogation des IA (ChatGPT, Claude, Gemini, AI Overviews)...', duration: 3000 },
  8→  { icon: BarChart3, label: 'Analyse des 50+ critères AEO...', duration: 2500 },
  9→  { icon: CheckCircle, label: 'Génération du rapport...', duration: 1500 },
 10→];
 11→
 12→interface AnalyzeProps {
 13→  onAnalyze: (url: string) => void;
 14→  isAnalyzing: boolean;
 15→}
 16→
 17→const Analyze: React.FC<AnalyzeProps> = ({ onAnalyze, isAnalyzing }) => {
 18→  const [inputUrl, setInputUrl] = useState('');
 19→  const [currentStep, setCurrentStep] = useState(0);
 20→
 21→  useEffect(() => {
 22→    if (!isAnalyzing) { setCurrentStep(0); return; }
 23→    let step = 0;
 24→    setCurrentStep(0);
 25→    const timers: ReturnType<typeof setTimeout>[] = [];
 26→    let accumulated = 0;
 27→    analysisSteps.forEach((s, i) => {
 28→      if (i > 0) {
 29→        accumulated += analysisSteps[i - 1].duration;
 30→        timers.push(setTimeout(() => setCurrentStep(i), accumulated));
 31→      }
 32→    });
 33→    return () => timers.forEach(clearTimeout);
 34→  }, [isAnalyzing]);
 35→
 36→  const handleSubmit = (e: React.FormEvent) => {
 37→    e.preventDefault();
 38→    if (inputUrl && !isAnalyzing) {
 39→      onAnalyze(inputUrl);
 40→    }
 41→  };
 42→
 43→  return (
 44→    <div className="flex flex-col items-center justify-center page-enter">
 45→      <div className="text-center mb-10 space-y-4">
 46→        <div className="inline-flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.03] border border-white/[0.06] text-[var(--accent-text)] text-[13px] font-medium">
 47→          <Sparkles size={14} />
 48→          <span>Audit AEO & GEO Instantané</span>
 49→        </div>
 50→        <h1 className="text-4xl md:text-5xl font-semibold text-[var(--text-primary)] tracking-tight">
 51→          Analysez votre <span className="text-[var(--accent-text)]">visibilité IA</span>
 52→        </h1>
 53→        <p className="text-lg text-[var(--text-tertiary)] max-w-2xl mx-auto">
 54→          Découvrez comment les moteurs de réponse perçoivent votre contenu et obtenez un plan d'action pour être cité.
 55→        </p>
 56→      </div>
 57→
 58→      <div className="w-full max-w-3xl relative z-10">
 59→        <div className="absolute inset-0 bg-[var(--accent)]/10 blur-3xl rounded-full opacity-20 -z-10"></div>
 60→        <form onSubmit={handleSubmit}>
 61→          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-8">
 62→            <div className="flex items-center gap-3">
 63→              <Search className="text-[var(--text-disabled)] shrink-0" size={24} />
 64→              <input
 65→                type="url"
 66→                required
 67→                placeholder="https://votre-site.com"
 68→                className="w-full bg-[var(--bg-base)] border border-white/[0.06] rounded-lg focus:ring-1 focus:ring-[var(--accent)]/30 focus:border-[var(--accent)]/30 text-[var(--text-primary)] placeholder-[var(--text-disabled)] text-lg px-4 py-4"
 69→                value={inputUrl}
 70→                onChange={(e) => setInputUrl(e.target.value)}
 71→                autoFocus
 72→              />
 73→              <button
 74→                type="submit"
 75→                disabled={isAnalyzing}
 76→                className={`px-8 py-4 shrink-0 bg-white text-black font-medium rounded-lg hover:bg-gray-200 transition-all ${isAnalyzing ? '!bg-white/[0.06] !text-[var(--text-disabled)] cursor-not-allowed opacity-60' : ''}`}
 77→              >
 78→                {isAnalyzing ? 'Analyse...' : 'Lancer l\'audit'}
 79→              </button>
 80→            </div>
 81→          </div>
 82→        </form>
 83→
 84→        {!isAnalyzing && (
 85→          <div className="flex justify-center gap-8 mt-8 text-[13px] text-[var(--text-tertiary)]">
 86→            <span className="flex items-center gap-2"><ShieldCheck size={16} className="text-[var(--accent-text)]"/> Analyse Sécurisée</span>
 87→            <span className="flex items-center gap-2"><TrendingUp size={16} className="text-[var(--accent-text)]"/> +50 Critères GEO</span>
 88→          </div>
 89→        )}
 90→
 91→        {isAnalyzing && (
 92→          <div className="mt-8 w-full max-w-md mx-auto space-y-3">
 93→            {analysisSteps.map((step, i) => {
 94→              const StepIcon = step.icon;
 95→              const isActive = i === currentStep;
 96→              const isDone = i < currentStep;
 97→              return (
 98→                <div key={i} className={`flex items-center gap-3 px-4 py-3 rounded-lg transition-all duration-500 ${
 99→                  isActive ? 'bg-[var(--accent-subtle)] border border-[var(--accent)]/20' : isDone ? 'bg-white/[0.03] border border-[var(--border-subtle)]' : 'opacity-40 border border-transparent'
100→                }`}>
101→                  <div className={`w-8 h-8 rounded-full flex items-center justify-center shrink-0 transition-all duration-300 ${
102→                    isDone ? 'bg-[var(--success)]/20' : isActive ? 'bg-[var(--accent-subtle)]' : 'bg-white/[0.03]'
103→                  }`}>
104→                    {isDone ? <CheckCircle size={16} className="text-[var(--success)]" /> : <StepIcon size={16} className={isActive ? 'text-[var(--accent-text)] animate-pulse' : 'text-[var(--text-disabled)]'} />}
105→                  </div>
106→                  <span className={`text-[13px] font-medium transition-colors duration-300 ${isDone ? 'text-[var(--success)]' : isActive ? 'text-[var(--accent-text)]' : 'text-[var(--text-disabled)]'}`}>{step.label}</span>
107→                  {isActive && <div className="ml-auto w-4 h-4 border-2 border-[var(--accent-text)] border-t-transparent rounded-full animate-spin" />}
108→                </div>
109→              );
110→            })}
111→            <div className="mt-4 w-full h-1.5 bg-white/[0.06] rounded-full overflow-hidden">
112→              <div className="h-full bg-[var(--accent)] rounded-full transition-all duration-1000 ease-out" style={{ width: `${((currentStep + 1) / analysisSteps.length) * 100}%` }} />
113→            </div>
114→          </div>
115→        )}
116→      </div>
117→
118→    </div>
119→  );
120→};
121→
122→export default Analyze;

  1→import React, { useState } from 'react';
  2→import { AnalysisResult, CategoryScore, GeneratedSolution, User } from '../types';
  3→import CategoryCard from '../components/CategoryCard';
  4→import { Info, Download, Share2, ScanLine, CheckCircle2, AlertTriangle, XCircle } from 'lucide-react';
  5→import html2canvas from 'html2canvas';
  6→import jsPDF from 'jspdf';
  7→import PageHeader from '../components/layout/PageHeader';
  8→
  9→interface Props {
 10→  data: AnalysisResult;
 11→  onBack: () => void;
 12→  user: User | null;
 13→  onDeductCredits: (amount: number) => boolean;
 14→  onSaveSolution: (analysisId: string, recId: string, solution: GeneratedSolution) => void;
 15→  initialTab?: 'details' | 'archives' | 'overview'; // Expanded type to include overview
 16→  onNewAnalysis?: () => void;
 17→}
 18→
 19→const Results: React.FC<Props> = ({ data, onBack, user, onDeductCredits, onSaveSolution, onNewAnalysis }) => {
 20→  const [isExporting, setIsExporting] = useState(false);
 21→
 22→  const categoryScores = Object.values(data.categories) as CategoryScore[];
 23→
 24→  const handleDownloadPDF = async () => {
 25→    const element = document.getElementById('full-pdf-report');
 26→    if (!element) return;
 27→
 28→    setIsExporting(true);
 29→    try {
 30→      // Wait a moment for the hidden div to render properly
 31→      await new Promise(resolve => setTimeout(resolve, 500));
 32→
 33→      const canvas = await html2canvas(element, {
 34→        scale: 2,
 35→        useCORS: true,
 36→        logging: false,
 37→        windowWidth: 1000 // Force width to match container style
 38→      });
 39→
 40→      const imgData = canvas.toDataURL('image/jpeg', 0.95);
 41→      const pdf = new jsPDF({
 42→        orientation: 'portrait',
 43→        unit: 'mm',
 44→        format: 'a4'
 45→      });
 46→
 47→      const pdfWidth = pdf.internal.pageSize.getWidth();
 48→      const pdfHeight = pdf.internal.pageSize.getHeight();
 49→      const imgWidth = pdfWidth;
 50→      const imgHeight = (canvas.height * imgWidth) / canvas.width;
 51→      
 52→      let heightLeft = imgHeight;
 53→      let position = 0;
 54→
 55→      // First page
 56→      pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 57→      heightLeft -= pdfHeight;
 58→
 59→      // Subsequent pages if content overflows
 60→      while (heightLeft > 0) {
 61→        position = heightLeft - imgHeight;
 62→        pdf.addPage();
 63→        pdf.addImage(imgData, 'JPEG', 0, position, imgWidth, imgHeight);
 64→        heightLeft -= pdfHeight;
 65→      }
 66→      
 67→      const hostname = new URL(data.url).hostname;
 68→      pdf.save(`Audit_AEO_${hostname}_${new Date().toISOString().split('T')[0]}.pdf`);
 69→    } catch (err) {
 70→      console.error('PDF Export failed', err);
 71→      alert('Erreur lors de la génération du PDF.');
 72→    } finally {
 73→      setIsExporting(false);
 74→    }
 75→  };
 76→
 77→  const handleShare = async () => {
 78→    const shareData = {
 79→      title: 'Rapport AEO - CitedBy.ai',
 80→      text: `Découvrez l'analyse AEO pour ${data.url} sur CitedBy.ai`,
 81→      url: window.location.href,
 82→    };
 83→
 84→    try {
 85→      if (navigator.share) {
 86→        await navigator.share(shareData);
 87→      } else {
 88→        await navigator.clipboard.writeText(window.location.href);
 89→        alert('Lien du rapport copié dans le presse-papier !');
 90→      }
 91→    } catch (err) {
 92→      console.error('Share failed', err);
 93→    }
 94→  };
 95→
 96→  return (
 97→    <div className="relative page-enter">
 98→
 99→      {/* Header */}
100→      <PageHeader title={new URL(data.url).hostname} description={`Analysé le ${new Date(data.timestamp).toLocaleDateString()} à ${new Date(data.timestamp).toLocaleTimeString()}`} />
101→
102→      {/* Actions bar */}
103→      <div className="flex flex-col md:flex-row items-start md:items-center justify-between mb-8 gap-4">
104→        <div className="flex items-center gap-3">
105→          <button
106→            onClick={handleShare}
107→            className="flex items-center gap-2 px-4 py-2 border border-white/[0.06] bg-white/[0.03] hover:bg-white/[0.06] rounded-lg text-[13px] text-[var(--text-secondary)] transition-colors"
108→          >
109→            <Share2 size={14} /> Partager
110→          </button>
111→          <button
112→            onClick={handleDownloadPDF}
113→            disabled={isExporting}
114→            className="flex items-center gap-2 px-4 py-2 border border-white/[0.06] bg-white/[0.03] hover:bg-white/[0.06] rounded-lg text-[13px] text-[var(--accent-text)] font-medium transition-colors"
115→          >
116→            {isExporting ? (
117→                <>
118→                    <div className="animate-spin h-3.5 w-3.5 border-2 border-[var(--accent)] border-t-transparent rounded-full"></div>
119→                    Génération...
120→                </>
121→            ) : (
122→                <>
123→                    <Download size={14} /> Générer PDF
124→                </>
125→            )}
126→          </button>
127→        </div>
128→        {onNewAnalysis && (
129→            <button
130→                onClick={onNewAnalysis}
131→                className="flex items-center gap-2 px-4 py-2 bg-white text-black text-[13px] font-medium rounded-lg hover:bg-gray-200 transition-all cursor-pointer"
132→            >
133→                <ScanLine size={14} /> Nouvel audit
134→            </button>
135→        )}
136→      </div>
137→
138→      {/* Content - Category cards */}
139→      <div className="min-h-[500px]">
140→          <div className="space-y-6">
141→            <h3 className="text-[15px] font-semibold text-[var(--text-primary)] mb-4">Analyse détaillée par catégorie</h3>
142→
143→            <div className="grid md:grid-cols-2 gap-4">
144→              {categoryScores.map((cat, i) => (
145→                <CategoryCard key={i} category={cat} />
146→              ))}
147→            </div>
148→
149→            {/* --- PROFESSIONAL PDF REPORT CONTAINER (HIDDEN) --- */}
150→            <div 
151→              id="full-pdf-report" 
152→              className="bg-white text-black font-sans"
153→              style={{
154→                position: 'absolute',
155→                top: 0,
156→                left: '-9999px',
157→                width: '1000px', 
158→                padding: '60px',
159→              }}
160→            >
161→              {/* PAGE 1: COVER */}
162→              <div className="flex flex-col h-[1300px] relative border-b-2 border-gray-100 mb-10 pb-10">
163→                  {/* Header Logo */}
164→                  <div className="flex justify-between items-center mb-20">
165→                      <div className="flex items-center gap-3">
166→                          <div className="w-12 h-12 rounded bg-[#a855f7] flex items-center justify-center text-white font-serif font-bold text-3xl">C</div>
167→                          <span className="font-serif text-3xl font-bold text-gray-900">CitedBy.ai</span>
168→                      </div>
169→                      <div className="text-right">
170→                          <p className="text-gray-500 text-sm">Rapport d'Audit AEO</p>
171→                          <p className="text-gray-900 font-bold">{new Date(data.timestamp).toLocaleDateString()}</p>
172→                      </div>
173→                  </div>
174→
175→                  {/* Title Section */}
176→                  <div className="text-center mt-20 mb-20">
177→                      <h1 className="text-5xl font-serif font-bold text-gray-900 mb-6 tracking-tight">Audit de Visibilité Générative</h1>
178→                      <p className="text-2xl text-gray-500">{new URL(data.url).hostname}</p>
179→                  </div>
180→
181→                  {/* Score Hero */}
182→                  <div className="flex justify-center mb-20">
183→                      <div className="relative w-64 h-64 flex items-center justify-center">
184→                          {/* We recreate a static SVG ring for PDF to avoid animation glitches */}
185→                          <svg viewBox="0 0 100 100" className="w-full h-full transform -rotate-90">
186→                              <circle cx="50" cy="50" r="45" fill="none" stroke="#f3f4f6" strokeWidth="8" />
187→                              <circle 
188→                                cx="50" 
189→                                cy="50" 
190→                                r="45" 
191→                                fill="none" 
192→                                stroke={data.globalScore >= 80 ? "#a855f7" : data.globalScore >= 50 ? "#c084fc" : "#ef4444"}
193→                                strokeWidth="8" 
194→                                strokeDasharray={`${(data.globalScore / 100) * 283} 283`}
195→                                strokeLinecap="round"
196→                              />
197→                          </svg>
198→                          <div className="absolute flex flex-col items-center">
199→                              <span className="text-6xl font-bold text-gray-900">{data.globalScore}</span>
200→                              <span className="text-sm font-bold text-gray-400 uppercase tracking-widest mt-2">Score Global</span>
201→                          </div>
202→                      </div>
203→                  </div>
204→
205→                  {/* Executive Summary */}
206→                  <div className="bg-gray-50 p-8 rounded-2xl border border-gray-200 mt-auto mb-10">
207→                      <h3 className="font-bold text-gray-900 text-lg mb-4 flex items-center gap-2">
208→                          <Info size={20} className="text-[#a855f7]" /> Synthèse de l'analyste
209→                      </h3>
210→                      <p className="text-gray-600 leading-relaxed mb-4">
211→                          L'analyse de <strong>{new URL(data.url).hostname}</strong> révèle une probabilité de citation par les assistants IA de <strong>{data.aiCitation.probability}%</strong>. 
212→                          {data.globalScore < 50 
213→                              ? " L'entité manque actuellement de signaux structurés pour être correctement identifiée par les Knowledge Graphs."
214→                              : " L'entité possède une base solide mais nécessite des optimisations sémantiques pour garantir la primauté de la réponse."}
215→                      </p>
216→                      <div className="grid grid-cols-3 gap-6 pt-4 border-t border-gray-200">
217→                          <div>
218→                              <p className="text-xs text-gray-500 uppercase font-bold">Confiance</p>
219→                              <p className="text-lg font-bold text-gray-900">{data.categories['trust']?.score || 0}/100</p>
220→                          </div>
221→                          <div>
222→                              <p className="text-xs text-gray-500 uppercase font-bold">Technique</p>
223→                              <p className="text-lg font-bold text-gray-900">{data.categories['technical']?.score || 0}/100</p>
224→                          </div>
225→                          <div>
226→                              <p className="text-xs text-gray-500 uppercase font-bold">Autorité</p>
227→                              <p className="text-lg font-bold text-gray-900">{data.categories['entity']?.score || 0}/100</p>
228→                          </div>
229→                      </div>
230→                  </div>
231→              </div>
232→
233→              {/* PAGE 2+: RAPPORT D'AUDIT DÉTAILLÉ (pas de plan d'action) */}
234→              <div style={{ display: 'flex', flexDirection: 'column' }}>
235→                  {/* Section Header */}
236→                  <div style={{ marginBottom: '32px', borderBottom: '3px solid #a855f7', paddingBottom: '12px' }}>
237→                      <h2 style={{ fontSize: '24px', fontWeight: 700, color: '#111827', margin: '0 0 4px 0', fontFamily: 'Georgia, serif' }}>
238→                          Rapport d'Audit Détaillé
239→                      </h2>
240→                      <p style={{ fontSize: '13px', color: '#6b7280', margin: 0 }}>
241→                          Analyse de {categoryScores.length} catégories — {categoryScores.reduce((sum, c) => sum + c.items.length, 0)} critères évalués
242→                      </p>
243→                  </div>
244→
245→                  {/* TABLEAU RÉCAPITULATIF */}
246→                  <table style={{ width: '100%', borderCollapse: 'collapse', marginBottom: '40px', borderRadius: '8px', overflow: 'hidden', border: '1px solid #e5e7eb' }}>
247→                      <thead>
248→                          <tr style={{ backgroundColor: '#f8f5ff' }}>
249→                              <th style={{ padding: '12px 16px', textAlign: 'left', fontSize: '11px', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe' }}>Catégorie</th>
250→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#6b7280', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '80px' }}>Score</th>
251→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#16a34a', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Conforme</th>
252→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#d97706', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Alerte</th>
253→                              <th style={{ padding: '12px 16px', textAlign: 'center', fontSize: '11px', fontWeight: 700, color: '#dc2626', textTransform: 'uppercase', letterSpacing: '0.05em', borderBottom: '2px solid #d8b4fe', width: '70px' }}>Échec</th>
254→                          </tr>
255→                      </thead>
256→                      <tbody>
257→                          {categoryScores.map((cat, i) => {
258→                              const successCount = cat.items.filter(item => item.status === 'success').length;
259→                              const warningCount = cat.items.filter(item => item.status === 'warning').length;
260→                              const errorCount = cat.items.filter(item => item.status === 'error').length;
261→                              return (
262→                                  <tr key={i} style={{ backgroundColor: i % 2 === 0 ? '#ffffff' : '#fafafa' }}>
263→                                      <td style={{ padding: '10px 16px', fontSize: '13px', fontWeight: 600, color: '#111827', borderBottom: '1px solid #f3f4f6' }}>{cat.name}</td>
264→                                      <td style={{ padding: '10px 16px', textAlign: 'center', borderBottom: '1px solid #f3f4f6' }}>
265→                                          <span style={{
266→                                              display: 'inline-block', padding: '2px 14px', borderRadius: '12px', fontSize: '13px', fontWeight: 700,
267→                                              backgroundColor: cat.score >= 80 ? '#f0fdf4' : cat.score >= 50 ? '#faf5ff' : '#fef2f2',
268→                                              color: cat.score >= 80 ? '#16a34a' : cat.score >= 50 ? '#7c3aed' : '#dc2626',
269→                                          }}>{cat.score}</span>
270→                                      </td>
271→                                      <td style={{ padding: '10px 16px', textAlign: 'center', fontSize: '13px', fontWeight: 600, color: '#16a34a', borderBottom: '1px solid #f3f4f6' }}>{successCount}</td>
